PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT (SAMPLE(xsd:integer(?amount)) AS ?duration)
WHERE {
  ?series wdt:P1346 wd:Q504309 ;
          wdt:P582 ?endDate .
  FILTER(YEAR(?endDate) >= 1985)

  ?game wdt:P361 ?series ;
        wdt:P1923 wd:Q504309 ;
        wdt:P2047 ?gameDuration .

  ?gameDuration wikibase:quantityAmount ?amount ;
                wikibase:quantityUnit wd:Q7727 .

  FILTER(xsd:integer(?amount) > 0)
}
ORDER BY ASC(xsd:integer(?amount))
OFFSET 3
LIMIT 1

PREFIX wd: <http://www.wikidata.org/entity/>
PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wikibase: <http://wikiba.se/ontology#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>

SELECT ?duration
WHERE {
  ?series wdt:P1346 wd:Q504309 ; 
          wdt:P585 ?endDate .
  FILTER(YEAR(?endDate) >= 1985)

  ?game wdt:P361 ?series ; 
        wdt:P1923 wd:Q504309 ; 
        wdt:P2047 ?durationQuantity .

  ?durationQuantity wikibase:quantityAmount ?amount ;
                    wikibase:quantityUnit wd:Q7727 .

  BIND(xsd:integer(?amount) AS ?duration)
  FILTER(?duration > 0)
}
ORDER BY ASC(?duration)
OFFSET 3
LIMIT 1
